SELECT  FROM post_invest_tracking
WHERE del_flag = '0'
AND project_id = #{projectId}
AND tracking_year = #{trackingYear}
AND risk_level = #{riskLevel}
AND tracking_status = #{trackingStatus}
ORDER BY tracking_year DESC, tracking_period DESC

